import React, { Suspense } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import Layout from './components/Layout';
import { useAuth } from './context/AuthContext';

// Lazy loaded components for faster initial load
const Dashboard = React.lazy(() => import('./components/Dashboard'));
const Library = React.lazy(() => import('./components/Library'));
const Albums = React.lazy(() => import('./components/Albums'));
const AlbumDetails = React.lazy(() => import('./components/AlbumDetails'));
const Favorites = React.lazy(() => import('./components/Favorites'));
const Details = React.lazy(() => import('./components/Details'));
const Admin = React.lazy(() => import('./components/Admin'));
const Login = React.lazy(() => import('./components/Login'));
const UsersManagement = React.lazy(() => import('./components/UsersManagement'));
const WelcomeAuth = React.lazy(() => import('./components/WelcomeAuth'));
const UserProfile = React.lazy(() => import('./components/UserProfile'));

// Loading component
const PageLoader = () => (
  <div style={{ 
    display: 'flex', 
    justifyContent: 'center', 
    alignItems: 'center', 
    height: '60vh',
    fontSize: '1.2rem',
    color: 'var(--text-muted)'
  }}>
    <div className="search-spinner" style={{ marginRight: '12px' }} />
    Loading...
  </div>
);

function AdminRoute({ children }) {
  const { isAdmin } = useAuth();
  if (!isAdmin) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '50vh', textAlign: 'center', color: 'var(--text-muted)' }}>
        <i className="fas fa-lock" style={{ fontSize: '3rem', color: '#e53e3e', marginBottom: '16px' }} />
        <h2 style={{ color: 'var(--text-main)', marginBottom: '8px' }}>Access Denied</h2>
        <p>This section is restricted to Administrator users only.</p>
      </div>
    );
  }
  return children;
}

function StaffRoute({ children }) {
  const { isAdmin, isOnlyUser } = useAuth();
  if (!isAdmin && !isOnlyUser) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '50vh', textAlign: 'center', color: 'var(--text-muted)' }}>
        <i className="fas fa-lock" style={{ fontSize: '3rem', color: '#e53e3e', marginBottom: '16px' }} />
        <h2 style={{ color: 'var(--text-main)', marginBottom: '8px' }}>Access Denied</h2>
        <p>You do not have permission to view the Admin control panel.</p>
      </div>
    );
  }
  return children;
}

function AppContent() {
  const { token } = useAuth();

  return (
    <Suspense fallback={<PageLoader />}>
      <Routes>
        {token ? (
          // Authenticated layout shell
          <Route path="/" element={<Layout />}>
            <Route index element={<Dashboard />} />
            <Route path="library" element={<Library />} />
            <Route path="albums" element={<Albums />} />
            <Route path="albums/:id" element={<AlbumDetails />} />
            <Route path="favorites" element={<Favorites />} />
            <Route path="profile" element={<UserProfile />} />
            <Route path="details/:id" element={<Details />} />
            <Route path="admin" element={<StaffRoute><Admin /></StaffRoute>} />
            <Route path="users" element={<AdminRoute><UsersManagement /></AdminRoute>} />
            {/* Catch-all redirects back to Home */}
            <Route path="*" element={<Dashboard />} />
          </Route>
        ) : (
          // Unauthenticated screen: Admin login or Public login/register
          <>
            <Route path="/login" element={<Login />} />
            <Route path="*" element={<WelcomeAuth />} />
          </>
        )}
      </Routes>
    </Suspense>
  );
}

function App() {
  return (
    <Router>
      <Toaster
        position="top-right"
        toastOptions={{
          duration: 3000,
          style: {
            borderRadius: '12px',
            background: '#1f2937',
            color: '#fff',
            fontSize: '0.88rem',
            fontWeight: 500,
            boxShadow: '0 4px 20px rgba(0,0,0,0.18)',
          },
          success: {
            iconTheme: { primary: '#f7a84d', secondary: '#fff' },
          },
          error: {
            iconTheme: { primary: '#e53e3e', secondary: '#fff' },
          },
        }}
      />
      <AppContent />
    </Router>
  );
}

export default App;
